// Tuya Cloud API proxy — Cafe Fermentacion LP&ET
// Reemplazar las constantes con los valores reales antes de activar el workflow.
const crypto = require('crypto');

const ACCESS_ID     = '__TUYA_ACCESS_ID__';
const ACCESS_SECRET = '__TUYA_ACCESS_SECRET__';
const BASE_URL      = 'https://openapi.tuyaus.com';
const DEVICE_ID     = '__TUYA_DEVICE_ID__';

function sha256Hex(message) {
  return crypto.createHash('sha256').update(message, 'utf8').digest('hex');
}
function hmacSha256(key, message) {
  return crypto.createHmac('sha256', key).update(message, 'utf8').digest('hex').toUpperCase();
}

async function callTuya(method, path, accessToken = null) {
  const t = Date.now().toString();
  const contentSha = sha256Hex('');
  const stringToSign = `${method}\n${contentSha}\n\n${path}`;
  const signStr = accessToken
    ? `${ACCESS_ID}${accessToken}${t}${stringToSign}`
    : `${ACCESS_ID}${t}${stringToSign}`;
  const sign = hmacSha256(ACCESS_SECRET, signStr);

  const headers = {
    client_id: ACCESS_ID,
    sign,
    t,
    sign_method: 'HMAC-SHA256'
  };
  if (accessToken) headers.access_token = accessToken;

  const res = await this.helpers.httpRequest({
    method,
    url: `${BASE_URL}${path}`,
    headers,
    json: true
  });
  return res;
}

// 1) Token
const tokenRes = await callTuya.call(this, 'GET', '/v1.0/token?grant_type=1');
if (!tokenRes.success) {
  return [{ json: { ok: false, error: 'token_fail', detail: tokenRes } }];
}
const token = tokenRes.result.access_token;

// 2) Shadow properties
const shadowRes = await callTuya.call(this, 'GET', `/v2.0/cloud/thing/${DEVICE_ID}/shadow/properties`, token);
if (!shadowRes.success) {
  return [{ json: { ok: false, error: 'shadow_fail', detail: shadowRes } }];
}

// 3) Decode the 9 DPs
const props = shadowRes.result.properties || [];
const byCode = Object.fromEntries(props.map(p => [p.code, p]));
const val = (c, s) => { const p = byCode[c]; return p ? p.value / s : null; };
const tsOf = c => { const p = byCode[c]; return p ? p.time : null; };

const payload = {
  ok: true,
  device_id: DEVICE_ID,
  fetched_at: new Date().toISOString(),
  source_t: shadowRes.t,
  readings: {
    temp_c:       val('temp_current', 10),
    ph:           val('ph_current', 100),
    orp_mv:       val('orp_current', 1),
    sg:           val('pro_current', 1000),
    tds_ppm:      val('tds_current', 1),
    ec_us_cm:     val('ec_current', 1),
    salinity_ppm: val('salinity_current', 1),
    cf:           val('cf_current', 100),
    rh_pct:       val('rh_current', 1)
  },
  last_reading_t: tsOf('temp_current'),
  raw_count: props.length
};

return [{ json: payload }];
